class BLEDeviceServer:
    """BLE GATT Server for IoT device control and sensor data."""

    def __init__(self):
        self._ble = bluetooth.BLE()
        self._ble.active(True)
        self._ble.irq(self._irq_handler)

        self._connections = set()
        self._command_callbacks = []
        self._notify_enabled = {}

        # Initialize managers
        self._sensors = SensorManager()
        self._controller = DeviceController()

        # Register GATT services
        self._register_services()

        # Start advertising
        self._advertise()

        # Notification timer
        self._last_notify_time = time.ticks_ms()
        self._notify_interval_ms = 5000

        print("[BLE] Device server started: {}".format(DEVICE_NAME))

    def _register_services(self):
        """Register all GATT services and characteristics."""

        # Device Control Service
        _CONTROL_SERVICE = (
            _DEVICE_CONTROL_SERVICE_UUID,
            (
                # Command characteristic (write)
                (_COMMAND_CHAR_UUID, _FLAG_WRITE | _FLAG_WRITE_NO_RESPONSE),
                # Status characteristic (read + notify)
                (_STATUS_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                # Device name characteristic (read + write)
                (_DEVICE_NAME_CHAR_UUID, _FLAG_READ | _FLAG_WRITE),
                # Firmware version characteristic (read only)
                (_FIRMWARE_VER_CHAR_UUID, _FLAG_READ),
                # LED control characteristic (read + write)
                (_LED_CONTROL_CHAR_UUID, _FLAG_READ | _FLAG_WRITE | _FLAG_NOTIFY),
                # Relay control characteristic (read + write)
                (_RELAY_CONTROL_CHAR_UUID, _FLAG_READ | _FLAG_WRITE | _FLAG_NOTIFY),
            ),
        )

        # Sensor Data Service
        _SENSOR_SERVICE = (
            _SENSOR_DATA_SERVICE_UUID,
            (
                # Temperature characteristic (read + notify)
                (_TEMPERATURE_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                # Humidity characteristic (read + notify)
                (_HUMIDITY_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                # Light characteristic (read + notify)
                (_LIGHT_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
                # Battery characteristic (read + notify)
                (_BATTERY_CHAR_UUID, _FLAG_READ | _FLAG_NOTIFY),
            ),
        )

        # Register services and get handles
        (
            (
                self._handle_command,
                self._handle_status,
                self._handle_device_name,
                self._handle_firmware_ver,
                self._handle_led_control,
                self._handle_relay_control,
            ),
            (
                self._handle_temperature,
                self._handle_humidity,
                self._handle_light,
                self._handle_battery,
            ),
        ) = self._ble.gatts_register_services((_CONTROL_SERVICE, _SENSOR_SERVICE))

        # Set initial values
        self._ble.gatts_write(self._handle_device_name, DEVICE_NAME.encode())
        self._ble.gatts_write(self._handle_firmware_ver, FIRMWARE_VERSION.encode())
        self._ble.gatts_write(self._handle_status, self._controller.get_status_bytes())
        self._ble.gatts_write(self._handle_led_control, struct.pack("BB", 0, 255))
        self._ble.gatts_write(self._handle_relay_control, struct.pack("B", 0))

        # Update sensor values
        self._update_sensor_characteristics()

        print("[BLE] Services registered")

    def _irq_handler(self, event, data):
        """Handle BLE IRQ events."""

        if event == _IRQ_CENTRAL_CONNECT:
            conn_handle, addr_type, addr = data
            addr_str = ":".join(["{:02x}".format(b) for b in addr])
            print("[BLE] Connected: {} (handle={})".format(addr_str, conn_handle))
            self._connections.add(conn_handle)
            self._controller.state = "connected"
            # Flash LED to indicate connection
            self._controller.led_on()
            time.sleep_ms(200)
            self._controller.led_off()

        elif event == _IRQ_CENTRAL_DISCONNECT:
            conn_handle, addr_type, addr = data
            print("[BLE] Disconnected (handle={})".format(conn_handle))
            self._connections.discard(conn_handle)
            self._notify_enabled.pop(conn_handle, None)
            if not self._connections:
                self._controller.state = "idle"
            # Restart advertising
            self._advertise()

        elif event == _IRQ_GATTS_WRITE:
            conn_handle, attr_handle = data
            value = self._ble.gatts_read(attr_handle)
            self._handle_write(conn_handle, attr_handle, value)

        elif event == _IRQ_GATTS_READ_REQUEST:
            conn_handle, attr_handle = data
            self._handle_read_request(conn_handle, attr_handle)

    def _handle_write(self, conn_handle, attr_handle, value):
        """Process write requests to characteristics."""

        if attr_handle == self._handle_command:
            self._process_command(conn_handle, value)

        elif attr_handle == self._handle_device_name:
            new_name = value.decode("utf-8").strip()
            if new_name:
                print("[BLE] Device name changed to: {}".format(new_name))
                self._ble.gatts_write(self._handle_device_name, new_name.encode())

        elif attr_handle == self._handle_led_control:
            if len(value) >= 1:
                led_state = value[0]
                brightness = value[1] if len(value) >= 2 else 255
                if led_state:
                    self._controller.set_led_brightness(brightness)
                else:
                    self._controller.led_off()
                # Update characteristic
                self._ble.gatts_write(
                    self._handle_led_control,
                    struct.pack("BB", 1 if self._controller._led_state else 0, self._controller._led_brightness)
                )
                self._notify_characteristic(self._handle_led_control)
                self._update_status()

        elif attr_handle == self._handle_relay_control:
            if len(value) >= 1:
                relay_state = value[0]
                if relay_state:
                    self._controller.relay_on()
                else:
                    self._controller.relay_off()
                # Update characteristic
                self._ble.gatts_write(
                    self._handle_relay_control,
                    struct.pack("B", 1 if self._controller._relay_state else 0)
                )
                self._notify_characteristic(self._handle_relay_control)
                self._update_status()

    def _handle_read_request(self, conn_handle, attr_handle):
        """Update values before read requests."""

        if attr_handle == self._handle_temperature:
            temp = self._sensors.read_temperature()
            self._ble.gatts_write(self._handle_temperature, struct.pack("<f", temp))

        elif attr_handle == self._handle_humidity:
            humidity = self._sensors.read_humidity()
            self._ble.gatts_write(self._handle_humidity, struct.pack("<f", humidity))

        elif attr_handle == self._handle_light:
            light = self._sensors.read_light()
            self._ble.gatts_write(self._handle_light, struct.pack("<H", light))

        elif attr_handle == self._handle_battery:
            battery = self._sensors.read_battery()
            self._ble.gatts_write(self._handle_battery, struct.pack("<B", battery))

        elif attr_handle == self._handle_status:
            self._ble.gatts_write(self._handle_status, self._controller.get_status_bytes())

    def _process_command(self, conn_handle, value):
        """Process incoming command bytes."""

        if not value or len(value) < 1:
            self._send_response(conn_handle, STATUS_INVALID_CMD, b"")
            return

        cmd = value[0]
        params = value[1:] if len(value) > 1 else b""

        print("[BLE] Command received: 0x{:02x}, params: {}".format(cmd, params.hex() if params else "none"))

        response_status = STATUS_OK

        try:
            if cmd == CMD_LED_ON:
                self._controller.led_on()
                self._ble.gatts_write(
                    self._handle_led_control,
                    struct.pack("BB", 1, self._controller._led_brightness)
                )
                self._notify_characteristic(self._handle_led_control)

            elif cmd == CMD_LED_OFF:
                self._controller.led_off()
                self._ble.gatts_write(self._handle_led_control, struct.pack("BB", 0, 0))
                self._notify_characteristic(self._handle_led_control)

            elif cmd == CMD_RELAY_ON:
                self._controller.relay_on()
                self._ble.gatts_write(self._handle_relay_control, struct.pack("B", 1))
                self._notify_characteristic(self._handle_relay_control)

            elif cmd == CMD_RELAY_OFF:
                self._controller.relay_off()
                self._ble.gatts_write(self._handle_relay_control, struct.pack("B", 0))
                self._notify_characteristic(self._handle_relay_control)

            elif cmd == CMD_READ_SENSORS:
                self._update_sensor_characteristics()
                self._notify_all_sensors()

            elif cmd == CMD_GET_STATUS:
                pass  # Status will be sent in response

            elif cmd == CMD_SET_INTERVAL:
                if len(params) >= 2:
                    interval = struct.unpack("<H", params[:2])[0]
                    self._controller.set_sensor_interval(interval)
                    self._notify_interval_ms = interval * 1000
                else:
                    response_status = STATUS_INVALID_CMD

            elif cmd == CMD_BUZZER_ON:
                self._controller.buzzer_on()

            elif cmd == CMD_BUZZER_OFF:
                self._controller.buzzer_off()

            elif cmd == CMD_SET_BRIGHTNESS:
                if len(params) >= 1:
                    self._controller.set_led_brightness(params[0])
                    self._ble.gatts_write(
                        self._handle_led_control,
                        struct.pack("BB",
                                    1 if self._controller._led_state else 0,
                                    self._controller._led_brightness)
                    )
                    self._notify_characteristic(self._handle_led_control)
                else:
                    response_status = STATUS_INVALID_CMD

            elif cmd == CMD_RESET_DEVICE:
                print("[BLE] Soft reset requested")
                self._controller.led_off()
                self._controller.relay_off()
                self._controller.buzzer_off()

            elif cmd == CMD_FACTORY_RESET:
                self._controller.factory_reset()

            else:
                print("[BLE] Unknown command: 0x{:02x}".format(cmd))
                response_status = STATUS_INVALID_CMD

        except Exception as e:
            print("[BLE] Command error: {}".format(e))
            response_status = STATUS_ERROR

        # Update and notify status
        self._update_status()

        # Fire registered callbacks
        for callback in self._command_callbacks:
            try:
                callback(cmd, params, response_status)
            except Exception as e:
                print("[BLE] Callback error: {}".format(e))

    def _update_status(self):
        """Update status characteristic and notify."""
        self._ble.gatts_write(self._handle_status, self._controller.get_status_bytes())
        self._notify_characteristic(self._handle_status)

    def _update_sensor_characteristics(self):
        """Read all sensors and update characteristics."""
        readings = self._sensors.read_all()

        self._ble.gatts_write(
            self._handle_temperature,
            struct.pack("<f", readings["temperature"])
        )
        self._ble.gatts_write(
            self._handle_humidity,
            struct.pack("<f", readings["humidity"])
        )
        self._ble.gatts_write(
            self._handle_light,
            struct.pack("<H", readings["light"])
        )
        self._ble.gatts_write(
            self._handle_battery,
            struct.pack("<B", readings["battery"])
        )

        return readings

    def _notify_characteristic(self, handle):
        """Send notification for a characteristic to all connected clients."""
        for conn_handle in self._connections:
            try:
                self._ble.gatts_notify(conn_handle, handle)
            except Exception as e:
                print("[BLE] Notify error: {}".format(e))

    def _notify_all_sensors(self):
        """Send notifications for all sensor characteristics."""
        self._notify_characteristic(self._handle_temperature)
        self._notify_characteristic(self._handle_humidity)
        self._notify_characteristic(self._handle_light)
        self._notify_characteristic(self._handle_battery)

    def _send_response(self, conn_handle, status, data):
        """Send response via status characteristic."""
        response = struct.pack("B", status) + data
        self._ble.gatts_write(self._handle_status, response)
        try:
            self._ble.gatts_notify(conn_handle, self._handle_status)
        except Exception:
            pass

    def _advertise(self):
        """Start BLE advertising."""
        payload = _advertising_payload(
            name=DEVICE_NAME,
            services=[_DEVICE_CONTROL_SERVICE_UUID],
        )

        # Scan response with additional service UUID
        resp_payload = _advertising_payload(
            services=[_SENSOR_DATA_SERVICE_UUID],
        )

        try:
            self._ble.gap_advertise(
                100_000,  # Advertising interval in microseconds (100ms)
                adv_data=payload,
                resp_data=resp_payload,
            )
            print("[BLE] Advertising started")
        except Exception as e:
            print("[BLE] Advertising error: {}".format(e))

    def register_command_callback(self, callback):
        """Register a callback for command events: callback(cmd, params, status)."""
        self._command_callbacks.append(callback)

    def update(self):
        """Call periodically from main loop to handle notifications."""
        now = time.ticks_ms()

        if self._connections and time.ticks_diff(now, self._last_notify_time) >= self._notify_interval_ms:
            self._last_notify_time = now

            # Update and notify sensor data
            readings = self._update_sensor_characteristics()
            self._notify_all_sensors()

            print("[SENSORS] T={:.1f}°C H={:.1f}% L={}lux B={}%".format(
                readings["temperature"],
                readings["humidity"],
                readings["light"],
                readings["battery"],
            ))

    @property
    def is_connected(self):
        return len(self._connections) > 0

    @property
    def connection_count(self):
        return len(self._connections)

    @property
    def controller(self):
        return self._controller

    @property
    def sensors(self):
        return self._sensors

    def stop(self):
        """Stop BLE server."""
        self._ble.active(False)
        print("[BLE] Server stopped")


def on_command(cmd, params, status):
    """Example command callback."""
    status_str = "OK" if status == STATUS_OK else "ERROR"
    print("[APP] Command 0x{:02x} processed - {}".format(cmd, status_str))


