    print("Service UUIDs:")
    print("  Control: 12345678-1234-5678-1234-56789abcdef0")
    print("  Sensors: 12345678-1234-5678-1234-56789abcdef1")
    print("\nCommand reference:")
    print("  0x01=LED ON, 0x02=LED OFF")
    print("  0x03=Relay ON, 0x04=Relay OFF")
    print("  0x05=Read Sensors, 0x08=Get Status")
    print("  0x09=Buzzer ON, 0x0A=Buzzer OFF")
    print("  0x0B <brightness>=Set LED brightness")
    print("  0x07 <interval_le16>=Set sensor interval")
